const contacts = $input.all();

let entries = '';

// Fonction utilitaire : normalisation téléphone
const normalizePhone = (phone) => {
  let tel = (phone || '').replace(/[^0-9+]/g, '');

  if (tel.startsWith('+33')) {
    tel = '0' + tel.slice(3);
  }

  return tel;
};

// Génération des contacts
for (const item of contacts) {
  const c = item.json.properties || item.json;

  const firstname = c.firstname || '';
  const lastname  = c.lastname || '';
  const company   = c.company || '';
  const phone     = c.phone || c.mobilephone || '';

  if (!phone) continue; // ignorer si pas de numéro

  // Nom affiché : Prénom Nom (Société)
  let name = `${firstname} ${lastname}`.trim();

  if (company) {
    name += ` (${company})`;
  }

  name = name.substring(0, 50); // limite Yealink

  const tel = normalizePhone(phone);

  if (!tel) continue;

  entries +=
    `  <DirectoryEntry>\n` +
    `    <Name>${name}</Name>\n` +
    `    <Telephone>${tel}</Telephone>\n` +
    `  </DirectoryEntry>\n`;
}

// Postes internes
const internes = [
  { name: 'Assistante', tel: '100' },
  { name: 'Tech 1', tel: '101' },
  { name: 'Tech 2', tel: '102' },
  { name: 'Direction', tel: '103' },
  { name: 'Conférence', tel: '500' },
];

for (const { name, tel } of internes) {
  entries +=
    `  <DirectoryEntry>\n` +
    `    <Name>${name}</Name>\n` +
    `    <Telephone>${tel}</Telephone>\n` +
    `  </DirectoryEntry>\n`;
}

// XML final
const xml =
  `<?xml version="1.0" encoding="UTF-8"?>\n` +
  `<YealinkIPPhoneDirectory>\n` +
  `${entries}` +
  `</YealinkIPPhoneDirectory>`;

// Résultat
return [
  {
    json: {
      xml,
      count: contacts.length,
    },
  },
];

const items = $input.all();
